-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH union_data AS (
  SELECT * FROM {{ ref('int_union_aar_base_non_rgstrd') }}
),

dim_equipment_six AS (
  SELECT * FROM {{ ref('int_dim_equipment_six_lookup') }}
),

dim_equipment_six_nonrgstrd AS (
  SELECT * FROM {{ ref('int_dim_equipment_six_nonrgstrd_lookup') }}
),

max_dim_equipment AS (
  SELECT COALESCE(MAX(DIM_EQUIPMENT_ID), 0) AS max_id
  FROM {{ ref('dim_equipment') }}
)

SELECT
  u.* EXCLUDE (o_MAX_DIM_EQUIPMENT_ID),
  m.max_id AS o_MAX_DIM_EQUIPMENT_ID,

  -- MD5 calculations (simplified)
  MD5(CONCAT(
    COALESCE(u.AAR_CAR_CD, ''), '|',
    COALESCE(u.OWNER_MARK_CD, ''), '|',
    COALESCE(u.o_LESSEE_MARK_CD, ''), '|',
    COALESCE(u.PRIOR_EQPUN_NBR, ''), '|',
    COALESCE(u.PRIOR_MARK_CD, ''), '|',
    COALESCE(u.STNCL_MARK_OWNER_CLASS_CD, '')
  )) AS MD5_ID_SOURCE,

  MD5(CONCAT(
    COALESCE(d6.AAR_CAR_CD, ''), '|',
    COALESCE(d6.OWNER_MARK_CD, ''), '|',
    COALESCE(d6.LESSEE_MARK_CD, ''), '|',
    COALESCE(d6.PRIOR_EQPUN_NBR, ''), '|',
    COALESCE(d6.PRIOR_MARK_CD, ''), '|',
    COALESCE(d6.STNCL_MARK_OWNER_CLASS_CD, '')
  )) AS in_MD5_ID_TARGET,

  MD5(CONCAT(
    COALESCE(d6n.AAR_CAR_CD, ''), '|',
    COALESCE(d6n.OWNER_MARK_CD, ''), '|',
    COALESCE(d6n.LESSEE_MARK_CD, ''), '|',
    COALESCE(d6n.PRIOR_EQPUN_NBR, ''), '|',
    COALESCE(d6n.PRIOR_MARK_CD, ''), '|',
    COALESCE(d6n.STNCL_MARK_OWNER_CLASS_CD, '')
  )) AS MD5_ID_TARGET_NONRGSTRD,

  -- UCA Codes logic (simplified)
  CASE
    WHEN SUBSTR(u.AAR_CAR_CD, 1, 1) IN ('A', 'B') THEN '300'
    WHEN SUBSTR(u.AAR_CAR_CD, 1, 1) = 'C' THEN '311'
    ELSE NULL
  END AS UCA_CODES,

  CURRENT_TIMESTAMP() AS TYPE2_END_EFFECTV_DT

FROM union_data u
CROSS JOIN max_dim_equipment m
LEFT JOIN dim_equipment_six d6
  ON u.o_DIM_EQUIPMENT_ID = d6.DIM_EQUIPMENT_ID
LEFT JOIN dim_equipment_six_nonrgstrd d6n
  ON u.o_DIM_EQUIPMENT_ID = d6n.DIM_EQUIPMENT_ID
